import{_ as d,a as e,b as o,c as a,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as l}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as i,o as n,c,a2 as s}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"OCR 文字辨識使用說明","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Other/ocr.md","filePath":"zh-TW/Other/ocr.md","lastUpdated":1781962217000}'),h={name:"zh-TW/Other/ocr.md"};function p(b,t,g,P,u,m){return n(),c("div",null,[...t[0]||(t[0]=[s('<h1 id="ocr-文字辨識使用說明" tabindex="-1">OCR 文字辨識使用說明 <a class="header-anchor" href="#ocr-文字辨識使用說明" aria-label="Permalink to &quot;OCR 文字辨識使用說明&quot;">​</a></h1><p>OCR 文字辨識可以把圖片、掃描件、文件截圖中的文字辨識出來。</p><p>辨識完成後，可以直接複製結果，也可以匯出成 <code>Markdown</code>、<code>PDF</code>、<code>Word</code>，或把多種格式一起打包下載。</p><h2 id="這個功能能做什麼" tabindex="-1">這個功能能做什麼 <a class="header-anchor" href="#這個功能能做什麼" aria-label="Permalink to &quot;這個功能能做什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>說明</th></tr></thead><tbody><tr><td>圖片文字辨識</td><td>辨識圖片、截圖、掃描件裡的文字</td></tr><tr><td>文件版面辨識</td><td>對表格、公式、印章、圖文混排比較友善</td></tr><tr><td>多服務選擇</td><td>支援百度 PaddleOCR、Microsoft Azure Vision、Google Vision</td></tr><tr><td>結果複製</td><td>辨識完成後可直接複製文字結果</td></tr><tr><td>匯出檔案</td><td>支援匯出 Markdown、PDF、Word</td></tr><tr><td>批次打包</td><td>多個檔案辨識後，可把結果打包下載</td></tr></tbody></table><h2 id="先設定辨識服務" tabindex="-1">先設定辨識服務 <a class="header-anchor" href="#先設定辨識服務" aria-label="Permalink to &quot;先設定辨識服務&quot;">​</a></h2><p>入口在：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 其他設定 -&gt; OCR 文字辨識</span></span></code></pre></div><p><img src="'+d+'" alt="IP 定位和 OCR 文字辨識" loading="lazy"></p><p>這裡可以填不同服務的憑證：</p><table tabindex="0"><thead><tr><th>服務</th><th>後台要填什麼</th><th>適合情境</th></tr></thead><tbody><tr><td>百度 PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>推薦優先使用，適合文件、圖片、表格、圖文混排</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> 和 <code>Azure Vision API Key</code></td><td>適合已使用 Microsoft 雲端服務的使用者</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>；服務帳號 <code>JSON</code> 只用於查詢用量</td><td>適合使用 Google Cloud 的使用者</td></tr></tbody></table><p>填好後按儲存。</p><p>如果只是先試用，可以先設定一個服務，不需要三個都填。</p><h2 id="google-vision-怎麼設定" tabindex="-1">Google Vision 怎麼設定 <a class="header-anchor" href="#google-vision-怎麼設定" aria-label="Permalink to &quot;Google Vision 怎麼設定&quot;">​</a></h2><p>Google 這裡分兩件事：</p><table tabindex="0"><thead><tr><th>要做什麼</th><th>需要準備什麼</th></tr></thead><tbody><tr><td>使用 OCR</td><td>啟用 <code>Cloud Vision API</code>，再建立 <code>API Key</code></td></tr><tr><td>查詢使用次數</td><td>建立服務帳號，授予 <code>Monitoring Viewer</code> 角色，再下載服務帳號 <code>JSON</code></td></tr></tbody></table><p><img src="'+l+'" alt="Google API Key 和服務帳號截圖" loading="lazy"></p><h3 id="用-google-做-ocr" tabindex="-1">用 Google 做 OCR <a class="header-anchor" href="#用-google-做-ocr" aria-label="Permalink to &quot;用 Google 做 OCR&quot;">​</a></h3><ol><li>打開 Google Cloud Console。</li><li>進入 <code>API 和服務</code>。</li><li>打開 <code>程式庫</code>，搜尋並啟用 <code>Cloud Vision API</code>。</li><li>回到 <code>憑證</code>。</li><li>建立 <code>API Key</code>。</li><li>打開這組 API Key，複製金鑰內容。</li><li>回到 ImgBed 後台，貼到 <code>Google Vision API Key</code>。</li><li>儲存。</li></ol><p>這樣就可以在 OCR 彈窗裡選 Google Vision 來辨識圖片。</p><h3 id="查詢-google-使用次數" tabindex="-1">查詢 Google 使用次數 <a class="header-anchor" href="#查詢-google-使用次數" aria-label="Permalink to &quot;查詢 Google 使用次數&quot;">​</a></h3><p>查詢額度不是辨識必需項，只是用來查看 Google Vision 最近 30 天大約用了多少次。</p><ol><li>在 Google Cloud Console 進入 <code>IAM 和管理</code>。</li><li>打開 <code>服務帳號</code>。</li><li>建立服務帳號，例如 <code>vision-monitor</code>。</li><li>給這個服務帳號 <code>Monitoring Viewer</code> 角色。</li><li>進入服務帳號詳情，建立金鑰。</li><li>金鑰類型選 <code>JSON</code>。</li><li>下載產生的 JSON 檔。</li><li>回 ImgBed 後台，在服務帳號 JSON 欄位匯入。</li><li>匯入成功後，再點查詢額度。</li></ol><p>簡單理解：</p><table tabindex="0"><thead><tr><th>項目</th><th>作用</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>實際用來辨識圖片</td></tr><tr><td>服務帳號 <code>JSON</code></td><td>用來查詢 Google Vision 用了多少次</td></tr><tr><td><code>Monitoring Viewer</code> 角色</td><td>讓服務帳號可以讀取用量資料</td></tr></tbody></table><h2 id="取得百度-paddleocr-token" tabindex="-1">取得百度 PaddleOCR Token <a class="header-anchor" href="#取得百度-paddleocr-token" aria-label="Permalink to &quot;取得百度 PaddleOCR Token&quot;">​</a></h2><p>百度 PaddleOCR 需要先取得存取 Token。</p><p><img src="'+e+'" alt="取得 PaddleOCR Token" loading="lazy"></p><p>在百度 PaddleOCR 頁面打開 <code>API</code> 呼叫視窗，點取得 Token，然後複製 Token 內容。</p><p>回到 ImgBed 後台，把 Token 貼到 <code>PaddleOCR Token</code> 並儲存。</p><h2 id="開始辨識" tabindex="-1">開始辨識 <a class="header-anchor" href="#開始辨識" aria-label="Permalink to &quot;開始辨識&quot;">​</a></h2><p>在檔案管理裡選中一張圖片或文件截圖，點 <code>OCR</code> 按鈕。</p><p><img src="'+o+'" alt="OCR 辨識截圖" loading="lazy"></p><p>彈窗裡可以選辨識服務和模型。</p><p>百度 PaddleOCR 常用模型可這樣選：</p><table tabindex="0"><thead><tr><th>模型</th><th>適合情境</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>推薦預設使用，適合文件、表格、公式、印章、圖文混排</td></tr><tr><td><code>PP-OCRv5</code></td><td>適合簡單圖片、普通文字、輕量辨識</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>適合多語、複雜圖片、圖表類內容</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>適合更複雜的文件頁面和版面還原</td></tr></tbody></table><p>不確定選哪個時，先用 <code>PP-StructureV3</code>。</p><h2 id="進階選項" tabindex="-1">進階選項 <a class="header-anchor" href="#進階選項" aria-label="Permalink to &quot;進階選項&quot;">​</a></h2><p>辨識彈窗裡有進階選項，常見理解如下：</p><table tabindex="0"><thead><tr><th>選項</th><th>說明</th></tr></thead><tbody><tr><td>方向校正</td><td>圖片拍歪或旋轉時可以開</td></tr><tr><td>文件展平</td><td>拍照文件有彎曲、傾斜時可以開</td></tr><tr><td>版面偵測</td><td>想保留標題、段落、表格、圖片結構時建議開</td></tr><tr><td>圖表辨識</td><td>圖片裡有圖表或複雜結構時再開</td></tr><tr><td>美化 Markdown</td><td>匯出 Markdown 時比較容易閱讀</td></tr></tbody></table><p>一般截圖可以少開選項；掃描文件可以多開一些。</p><h2 id="查看辨識結果" tabindex="-1">查看辨識結果 <a class="header-anchor" href="#查看辨識結果" aria-label="Permalink to &quot;查看辨識結果&quot;">​</a></h2><p>辨識完成後，彈窗會顯示結果。</p><p>可以直接複製，也可以選擇匯出格式後匯出。</p><p><img src="'+a+'" alt="PDF 辨識截圖" loading="lazy"></p><p>如果辨識的是文件頁面，PDF 匯出後可以保留頁面效果，文字也可以搜尋。這類結果適合保存原始版面，後續查找內容也方便。</p><h2 id="匯出格式怎麼選" tabindex="-1">匯出格式怎麼選 <a class="header-anchor" href="#匯出格式怎麼選" aria-label="Permalink to &quot;匯出格式怎麼選&quot;">​</a></h2><table tabindex="0"><thead><tr><th>匯出格式</th><th>適合情境</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>整理筆記、貼到文件系統、後續繼續編輯</td></tr><tr><td><code>PDF (.pdf)</code></td><td>保留頁面效果，保存掃描件辨識結果</td></tr><tr><td><code>Word (.docx)</code></td><td>繼續排版、修改文字、交給別人編輯</td></tr><tr><td>全部匯出</td><td>同時保存多種格式和原圖，適合重要檔案歸檔</td></tr></tbody></table><p>如果只是要文字，匯出 Markdown 最輕。</p><p>如果還要頁面效果，匯出 PDF 或 Word 會更合適。</p><h2 id="word-效果" tabindex="-1">Word 效果 <a class="header-anchor" href="#word-效果" aria-label="Permalink to &quot;Word 效果&quot;">​</a></h2><p>匯出 Word 後，可以用 Office 軟體打開繼續編輯。</p><p><img src="'+r+`" alt="Word 辨識結果" loading="lazy"></p><p>有些文件會把辨識到的圖片、標題、段落一起放進 Word。效果會受到原圖清晰度、模型選擇、文件複雜度影響。</p><h2 id="哪些檔案更適合辨識" tabindex="-1">哪些檔案更適合辨識 <a class="header-anchor" href="#哪些檔案更適合辨識" aria-label="Permalink to &quot;哪些檔案更適合辨識&quot;">​</a></h2><table tabindex="0"><thead><tr><th>檔案類型</th><th>建議</th></tr></thead><tbody><tr><td>清楚截圖</td><td>直接辨識即可</td></tr><tr><td>掃描件</td><td>優先用 <code>PP-StructureV3</code></td></tr><tr><td>拍照文件</td><td>可以開方向校正、文件展平</td></tr><tr><td>表格 / 公式 / 印章</td><td>優先用結構化模型</td></tr><tr><td>普通短文字圖片</td><td><code>PP-OCRv5</code> 通常就夠用</td></tr></tbody></table><p>圖片越清楚、文字越端正，辨識結果通常越好。</p><h2 id="常見情況" tabindex="-1">常見情況 <a class="header-anchor" href="#常見情況" aria-label="Permalink to &quot;常見情況&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情況</th><th>說明</th></tr></thead><tbody><tr><td>辨識失敗</td><td>先檢查對應服務的 Token 或 API Key 是否已儲存</td></tr><tr><td>辨識很慢</td><td>文件越複雜、圖片越大，等待時間越長</td></tr><tr><td>表格不完整</td><td>可以換結構化模型重新辨識</td></tr><tr><td>文字有錯字</td><td>原圖模糊、反光、傾斜時更容易出錯，可換更清楚的圖片</td></tr><tr><td>Word 裡圖片較多</td><td>結構化模型會保留部分辨識圖片，屬於正常情況</td></tr></tbody></table><h3 id="google-查詢額度失敗" tabindex="-1">Google 查詢額度失敗 <a class="header-anchor" href="#google-查詢額度失敗" aria-label="Permalink to &quot;Google 查詢額度失敗&quot;">​</a></h3><p>先檢查：</p><ol><li>是否已匯入服務帳號 JSON。</li><li>服務帳號是否有 <code>Monitoring Viewer</code> 角色。</li><li>目前專案是否已啟用 <code>Cloud Vision API</code>。</li></ol><p>如果只是辨識圖片，不查詢次數，可以先不管服務帳號 JSON，只填 <code>Google Vision API Key</code> 即可。</p><h2 id="快速流程" tabindex="-1">快速流程 <a class="header-anchor" href="#快速流程" aria-label="Permalink to &quot;快速流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打開系統設定</span></span>
<span class="line"><span>-&gt; 進入其他設定</span></span>
<span class="line"><span>-&gt; 填 OCR 服務憑證</span></span>
<span class="line"><span>-&gt; 儲存</span></span>
<span class="line"><span>-&gt; 回到檔案管理</span></span>
<span class="line"><span>-&gt; 選中檔案並點 OCR</span></span>
<span class="line"><span>-&gt; 選模型</span></span>
<span class="line"><span>-&gt; 等待辨識完成</span></span>
<span class="line"><span>-&gt; 複製結果或匯出 Markdown / PDF / Word</span></span></code></pre></div>`,65)])])}const x=i(h,[["render",p]]);export{y as __pageData,x as default};
